rowObjects.data:
{{
  (() => {
    const active = String(appsmith.store.activeVentil || "").trim();
    // 1. Richtige Zeile suchen
    const foundIndex = Stammdaten.data.findIndex(r => 
      String(r.Ventil_Links || "").trim() === active || 
      String(r.Ventil_Rechts || "").trim() === active
    );

    if (foundIndex === -1) return {};

    // 2. Richtung bestimmen
    const row = Stammdaten.data[foundIndex];
    const isRechts = String(row.Ventil_Rechts || "").trim() === active;
    const spaltenName = isRechts ? 'Status_Leer_Rechts' : 'Status_Leer_Links';

    // 3. Objekt mit dem Index-Key (Appsmith nutzt oft 'rowIndex' intern für Sheets) und den Daten zurückgeben
    return {
      "rowIndex": foundIndex, 
      [spaltenName]: true
    };
  })()
}}
